    // ---------------------------------------------------------------------
    // Content-type provider (static cache)
    // ---------------------------------------------------------------------
    // The Download endpoint resolves content types from the file extension via
    // a FileExtensionContentTypeProvider. Constructing a new provider on every
    // request is unnecessary work because its mapping is immutable and the
    // type is thread-safe after construction, so the controller must hoist a
    // single private static readonly instance for reuse. These tests specify
    // that structural change and will fail until the field is introduced.
    // ---------------------------------------------------------------------

    [Fact]
    public void FilesController_DeclaresPrivateStaticReadonlyContentTypeProviderField()
    {
        var field = typeof(FilesController).GetField(
            "ContentTypeProvider",
            BindingFlags.NonPublic | BindingFlags.Static);

        Assert.NotNull(field);
        Assert.True(field!.IsPrivate);
        Assert.True(field.IsStatic);
        Assert.True(field.IsInitOnly); // readonly
        Assert.Equal(typeof(FileExtensionContentTypeProvider), field.FieldType);
    }

    [Fact]
    public void FilesController_DeclaresExactlyOneContentTypeProviderField()
    {
        // Only the single cached provider field of this type may exist; no
        // stray instance fields or duplicate statics should be introduced.
        var fields = typeof(FilesController)
            .GetFields(BindingFlags.Public | BindingFlags.NonPublic |
                       BindingFlags.Static | BindingFlags.Instance)
            .Where(f => f.FieldType == typeof(FileExtensionContentTypeProvider))
            .ToList();

        var field = Assert.Single(fields);
        Assert.Equal("ContentTypeProvider", field!.Name);
    }

    [Fact]
    public void FilesController_ContentTypeProviderField_IsInitializedAndStable()
    {
        // The cached provider must be initialized (non-null) and the same
        // instance must be returned on every access, confirming a single
        // shared provider rather than a fresh allocation per read.
        var field = typeof(FilesController).GetField(
            "ContentTypeProvider",
            BindingFlags.NonPublic | BindingFlags.Static);

        Assert.NotNull(field);
        var first = field!.GetValue(null);
        var second = field.GetValue(null);

        Assert.NotNull(first);
        Assert.IsType<FileExtensionContentTypeProvider>(first);
        Assert.Same(first, second);
    }

